external_knowledge:
- A DNO is considered underperforming if their KPI value is below 90;
- Serious issues are defined as complaints with a high severity level;
- Active status implies the DNO is currently operating and not suspended or terminated.

sql:
SELECT dnos.dno_name, regions.region_name
FROM dnos
JOIN regions ON dnos.dno_id = regions.dno_id;

external_knowledge:
- 'beacon' is a metaphor for the unique identifier of the complaint (`complaint_id`).;
- 'wandering miner' is a metaphorical way of referring to the customer named 'Bob Smith'.;
- 'vast canopy' metaphorically represents the broader entity or network under which the complaint was filed, in this case 'Scottish and Southern Electricity Networks'.

sql:
SELECT dno_id, kpi_name, AVG(kpi_value) AS average_kpi_value 
FROM kpi_data 
GROUP BY dno_id, kpi_name;

SELECT d.dno_name, c.complaint_type, c.customer_name
FROM complaints c
JOIN dnos d ON c.dno_id = d.dno_id;

SELECT dnos.dno_name, kpi_data.kpi_value
FROM dnos
JOIN kpi_data ON dnos.dno_id = kpi_data.dno_id;

SELECT dno_id, dno_name
FROM dnos
WHERE dno_id = 1;

SELECT dno_name 
FROM dnos 
WHERE dno_id = (SELECT dno_id FROM regions WHERE region_id = 1);

SELECT AVG(kpi_value) AS average_fault_response_time
FROM kpi_data
WHERE kpi_name = 'Fault Response Time';

SELECT d.dno_name, r.region_name
FROM dnos d
INNER JOIN regions r ON d.dno_id = r.dno_id;

SELECT kpi_id, kpi_name, kpi_value
FROM kpi_data
WHERE dno_id = (SELECT dno_id FROM dnos WHERE dno_name = 'SP Energy Networks');

SELECT DISTINCT dno_id
FROM complaints
WHERE complaint_status = 'Resolved' AND complaint_severity = 'High';
